    localProbeEnvMap0,
    worldPosition,
    direction,
    roughness,
    localProbePosition0,
    localProbeBoxMin0,
    localProbeBoxMax0,
    localProbeTexelWidth0,
    localProbeTexelHeight0,
    localProbeMaxMip0
